  ('country', 'SG', '[{"code":"en","type":"official","coverage":1},{"code":"ms","type":"official","coverage":1},{"code":"zh","type":"official","coverage":1},{"code":"ta","type":"official","coverage":1}]'::jsonb, 'Singapore should recognize English, Malay, Mandarin Chinese, and Tamil as official while giving English full practical credit because it is the main working language and default language of most public-facing travel interactions.', 'multiofficial_language_with_english_default_override', '[{"kind":"official_tourism","title":"Visit Singapore: Do''s and Don''ts in Singapore","url":"https://www.visitsingapore.com/travel-guide-tips/travel-information/do-and-dont-singapore/","note":"Official tourism guidance says Singapore has four official languages and that English is the main language used in business and administration."},{"kind":"government_reference","title":"Singapore Government: Learn about Singapore","url":"https://www.gov.sg/article/learn-about-singapore","note":"Government guidance identifies Singapore''s official languages and explains English as the working language."}]'::jsonb),
