  ('country', 'ZM', '[{"code":"en","type":"official","coverage":1}]'::jsonb, 'Zambia should score English as the official traveler-facing language while recognizing that large local languages such as Bemba and Nyanja matter strongly in everyday life. Those local-language exact-code assignments can be expanded later in the reconciliation pass.', 'official_english_with_major_local_language_note_override', '[{"kind":"official_tourism","title":"Zambia Tourism: Facts about Zambia","url":"https://www.zambiatourism.com/travel-info/facts/","note":"Official tourism guidance lists English as Zambia''s official language and Bemba as the most spoken local language."},{"kind":"official_tourism","title":"Zambia Tourism: Tourist Guide general info","url":"https://www.zambiatourism.com/travel-info/general-info/","note":"Official tourism guidance says English is the official language, that business and media are conducted in English, and that most hospitality workers speak it fairly well."}]'::jsonb),
